import java.io.*;
import java.util.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Validate user input
        if (isValidInput(userInput)) {
            // Encode user input before displaying it
            String encodedUserInput = Encode.forHtml(userInput);
            System.out.println("Hello, " + encodedUserInput + "!");
        } else {
            System.out.println("Invalid input. Please try again.");
        }

        scanner.close();
    }

    // Validate user input to prevent XSS attacks
    private static boolean isValidInput(String userInput) {
        // Implement your validation logic here
        // For example, you can check for special characters or patterns

        return userInput.matches("^[a-zA-Z0-9 ]+$"); // Only allow letters, numbers, and spaces
    }
}

